const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return fallback;
  try {
    const parsed = JSON.parse(raw);
    return parsed === null || parsed === undefined ? fallback : parsed;
  } catch (e) {
    return fallback;
  }
}

const searchParams = safeParse('task1_searchParams', null);
const topArticleId = localStorage.getItem('task1_topArticleId') || '';
const openedArticleIdsRaw = safeParse('task1_openedArticleIds', []);
const openedArticleIds = Array.isArray(openedArticleIdsRaw) ? openedArticleIdsRaw : [];
const articles = safeParse('articles', []);

// Determine the expected top-cited CC BY open-access neuroscience article from 2021–2022
const qualifyingArticles = articles.filter(a => {
  if (!a || typeof a !== 'object') return false;
  if (typeof a.publicationYear !== 'number') return false;
  if (a.publicationYear < 2021 || a.publicationYear > 2022) return false;
  if (!Array.isArray(a.subjectAreas) || !a.subjectAreas.includes('neuroscience')) return false;
  if (a.accessType !== 'open_access') return false;
  if (a.license !== 'cc_by') return false;
  return true;
});

qualifyingArticles.sort((a, b) => (b.citationCount || 0) - (a.citationCount || 0));
const expectedTop = qualifyingArticles[0] || null;
const expectedTopId = expectedTop ? expectedTop.id : '';

// CP1 (0.30): User used correct search filters (years 2021–2022, open_access, CC BY, citations_desc)
const usedCorrectSearch = !!searchParams &&
  searchParams.publicationYearMin === 2021 &&
  searchParams.publicationYearMax === 2022 &&
  Array.isArray(searchParams.accessTypes) && searchParams.accessTypes.includes('open_access') &&
  Array.isArray(searchParams.licenses) && searchParams.licenses.includes('cc_by') &&
  searchParams.sortOption === 'citations_desc';
checkpoints.push({ passed: usedCorrectSearch, weight: 0.30 });

// CP2 (0.30): User's recorded top article matches the actual top-cited qualifying article
const selectedCorrectTop = !!expectedTopId && topArticleId === expectedTopId;
checkpoints.push({ passed: selectedCorrectTop, weight: 0.30 });

// CP3 (0.40): User opened the PDF for the correct top-cited qualifying article
const openedCorrectPdf = !!expectedTopId && openedArticleIds.includes(expectedTopId);
checkpoints.push({ passed: openedCorrectPdf, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

