const articles = safeParse('articles', []);
const readingLists = safeParse('reading_lists', []);
const items = safeParse('reading_list_items', []);

function isClimateImpactEnvSciArticle(a) {
  if (!a || typeof a !== 'object') return false;
  if (typeof a.publicationYear !== 'number') return false;
  if (a.publicationYear < 2019 || a.publicationYear > 2024) return false;
  if (!Array.isArray(a.subjectAreas) || !a.subjectAreas.includes('environmental_science')) return false;
  if (typeof a.citationCount !== 'number' || a.citationCount <= 50) return false;
  const textParts = [a.title || '', a.abstract || ''];
  if (Array.isArray(a.keywords)) textParts.push(a.keywords.join(' '));
  const text = textParts.join(' ').toLowerCase();
  if (!text.includes('climate')) return false;
  return true;
}

let maxQualifyingInAnyList = 0;

readingLists.forEach(list => {
  const listItemArticleIds = items
    .filter(i => i && i.readingListId === list.id)
    .map(i => i.articleId);
  const uniqueIds = Array.from(new Set(listItemArticleIds));
  const count = uniqueIds.reduce((acc, id) => {
    const art = articles.find(a => a && a.id === id) || null;
    return acc + (isClimateImpactEnvSciArticle(art) ? 1 : 0);
  }, 0);
  if (count > maxQualifyingInAnyList) maxQualifyingInAnyList = count;
});

// CP1–CP3: Number of qualifying articles in the best reading list (combined action+correctness)
[1, 2, 3].forEach((n, idx) => {
  const weight = n === 1 ? 0.34 : 0.33; // 0.34 + 0.33 + 0.33 = 1.00
  checkpoints.push({ passed: maxQualifyingInAnyList >= n, weight });
});

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

