const journals = safeParse('journals', []);
const comparedRaw = safeParse('task3_comparedJournalIds', []);
const comparedJournalIds = Array.isArray(comparedRaw) ? comparedRaw : [];
const selectedJournalId = localStorage.getItem('task3_selectedJournalId') || '';

// Determine top 3 computer science journals by impact factor
const csJournals = journals.filter(j => j && Array.isArray(j.subjectAreas) && j.subjectAreas.includes('computer_science'));
csJournals.sort((a, b) => (b.impactFactor || 0) - (a.impactFactor || 0));
const top3 = csJournals.slice(0, 3);
const top3Ids = top3.map(j => j.id);

// First qualifying journal in top 3 with APC <= 1500 and median review time <= 60 days
const expectedJournal = top3.find(j => {
  if (!j) return false;
  const apcOk = typeof j.apcAmount === 'number' && j.apcAmount <= 1500;
  const rtOk = typeof j.medianReviewTimeDays === 'number' && j.medianReviewTimeDays <= 60;
  return apcOk && rtOk;
}) || null;
const expectedJournalId = expectedJournal ? expectedJournal.id : '';

const selectedJournal = journals.find(j => j && j.id === selectedJournalId) || null;

// CP1 (0.30): Selected journal is a qualifying CS journal with APC <= 1500 and review time <= 60
const selectedQualifies = !!selectedJournal &&
  Array.isArray(selectedJournal.subjectAreas) && selectedJournal.subjectAreas.includes('computer_science') &&
  typeof selectedJournal.apcAmount === 'number' && selectedJournal.apcAmount <= 1500 &&
  typeof selectedJournal.medianReviewTimeDays === 'number' && selectedJournal.medianReviewTimeDays <= 60;
checkpoints.push({ passed: selectedQualifies, weight: 0.30 });

// CP2 (0.30): Selected journal is the first qualifying one in the top-3 impact factor list
const selectedIsExpected = !!expectedJournalId && selectedJournalId === expectedJournalId;
checkpoints.push({ passed: selectedIsExpected, weight: 0.30 });

// CP3 (0.40): Selected journal is among the top 3 and was explicitly compared/inspected
const comparedSelectedInTop3 = !!selectedJournalId && top3Ids.includes(selectedJournalId) && comparedJournalIds.includes(selectedJournalId);
checkpoints.push({ passed: comparedSelectedInTop3, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

