const articles = safeParse('articles', []);
const apaRaw = safeParse('task4_apaCitationArticleIds', []);
const apaArticleIds = Array.isArray(apaRaw) ? apaRaw : [];

// Determine top 2 cardiology clinical trial articles by sample size
const cardiologyTrials = articles.filter(a => {
  return a && a.articleType === 'clinical_trial' && Array.isArray(a.subjectAreas) && a.subjectAreas.includes('cardiology');
});
cardiologyTrials.sort((a, b) => (b.sampleSize || 0) - (a.sampleSize || 0));
const expectedTop2 = cardiologyTrials.slice(0, 2);
const expectedIds = expectedTop2.map(a => a.id);

const qualifyingCopiedIds = apaArticleIds.filter(id => expectedIds.includes(id));

// CP1 (0.50): APA citation copied for at least the top 1 largest-sample cardiology trial
checkpoints.push({ passed: qualifyingCopiedIds.length >= 1, weight: 0.50 });

// CP2 (0.50): APA citations copied for both of the top 2 largest-sample cardiology trials
checkpoints.push({ passed: qualifyingCopiedIds.length >= 2, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

