const articles = safeParse('articles', []);
const journals = safeParse('journals', []);
const items = safeParse('reading_list_items', []);
const openedRaw = safeParse('task5_fullTextArticleIds', []);
const openedArticleIds = Array.isArray(openedRaw) ? openedRaw : [];

function getJournal(journalId) {
  return journals.find(j => j && j.id === journalId) || null;
}

// Qualifying articles: 2023 review, >=11 pages, environmental journal/subject, has HTML URL
const qualifyingArticles = articles.filter(a => {
  if (!a || typeof a !== 'object') return false;
  if (a.publicationYear !== 2023) return false;
  if (a.articleType !== 'review_article') return false;
  if (typeof a.pageCount === 'number' && a.pageCount < 11) return false;
  const journal = getJournal(a.journalId);
  const articleHasEnv = Array.isArray(a.subjectAreas) && a.subjectAreas.includes('environmental_science');
  const journalHasEnv = journal && Array.isArray(journal.subjectAreas) && journal.subjectAreas.includes('environmental_science');
  if (!articleHasEnv && !journalHasEnv) return false;
  if (!a.htmlUrl) return false;
  return true;
});

const qualifyingIds = qualifyingArticles.map(a => a.id);
const openedQualifyingIds = openedArticleIds.filter(id => qualifyingIds.includes(id));

// Among opened qualifying articles, check if any was added to a reading list
const savedQualifyingIds = openedQualifyingIds.filter(id => items.some(it => it && it.articleId === id));

// CP1 (0.40): User opened HTML full text for at least one qualifying 2023 environmental review article
checkpoints.push({ passed: openedQualifyingIds.length >= 1, weight: 0.40 });

// CP2 (0.60): User also saved at least one such opened qualifying article to a reading list
checkpoints.push({ passed: savedQualifyingIds.length >= 1, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

