const alerts = safeParse('saved_search_alerts', []);

function nameMatches(alert) {
  return alert && typeof alert.name === 'string' && alert.name.trim().toLowerCase() === 'ml health weekly';
}

function cond1(alert) {
  return nameMatches(alert) && alert.frequency === 'weekly';
}

function cond2(alert) {
  if (!cond1(alert)) return false;
  const yearOk = typeof alert.publicationYearMin === 'number' && alert.publicationYearMin >= 2020;
  const sas = Array.isArray(alert.subjectAreas) ? alert.subjectAreas : [];
  const hasMed = sas.includes('medicine');
  const hasCS = sas.includes('computer_science');
  return yearOk && hasMed && hasCS;
}

function cond3(alert) {
  if (!cond2(alert)) return false;
  const sortOk = alert.sortOption === 'publication_date_newest';
  const q = (alert.queryString || '').toLowerCase();
  const hasML = q.includes('machine') && q.includes('learning');
  const hasHealth = q.includes('health') || q.includes('healthcare') || q.includes('medicine');
  return sortOk && hasML && hasHealth;
}

const alert1 = alerts.find(a => cond1(a)) || null;
const alert2 = alerts.find(a => cond2(a)) || null;
const alert3 = alerts.find(a => cond3(a)) || null;

// CP1 (0.30): Weekly alert with correct name
checkpoints.push({ passed: !!alert1, weight: 0.30 });

// CP2 (0.30): That alert also filters from 2020 onward and to Medicine + Computer Science
checkpoints.push({ passed: !!alert2, weight: 0.30 });

// CP3 (0.40): That alert additionally sorts by newest and has an ML + health-related query string
checkpoints.push({ passed: !!alert3, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

