const datasets = safeParse('datasets', []);
const articles = safeParse('articles', []);
const openedRaw = safeParse('task7_openedDatasetIds', []);
const viewedRaw = safeParse('task7_viewedFileListDatasetIds', []);
const openedDatasetIds = Array.isArray(openedRaw) ? openedRaw : [];
const viewedDatasetIds = Array.isArray(viewedRaw) ? viewedRaw : [];

function getArticle(articleId) {
  return articles.find(a => a && a.id === articleId) || null;
}

// Qualifying datasets: open, hasCsvFiles, linked to a Medicine article about gene expression
const qualifyingDatasets = datasets.filter(ds => {
  if (!ds || typeof ds !== 'object') return false;
  if (!ds.isOpenData) return false;
  if (!ds.hasCsvFiles) return false;
  const article = getArticle(ds.articleId);
  if (!article) return false;
  if (!Array.isArray(article.subjectAreas) || !article.subjectAreas.includes('medicine')) return false;
  const textParts = [
    ds.title || '',
    ds.description || '',
    ds.articleTitle || '',
    article.title || '',
    article.abstract || ''
  ];
  if (Array.isArray(article.keywords)) textParts.push(article.keywords.join(' '));
  const text = textParts.join(' ').toLowerCase();
  const isGeneExpression = text.includes('rna') || text.includes('transcript') || text.includes('gene expression');
  if (!isGeneExpression) return false;
  return true;
});

const qualifyingIds = qualifyingDatasets.map(ds => ds.id);
const openedQualifyingIds = openedDatasetIds.filter(id => qualifyingIds.includes(id));
const viewedQualifyingIds = viewedDatasetIds.filter(id => qualifyingIds.includes(id) && openedDatasetIds.includes(id));

// CP1 (0.40): User opened the details page of at least one qualifying gene expression CSV dataset
checkpoints.push({ passed: openedQualifyingIds.length >= 1, weight: 0.40 });

// CP2 (0.60): User also viewed the file list for at least one such opened qualifying dataset
checkpoints.push({ passed: viewedQualifyingIds.length >= 1, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

