const collections = safeParse('collections', []);
const items = safeParse('collection_items', []);
const articles = safeParse('articles', []);
const journals = safeParse('journals', []);

function getJournal(journalId) {
  return journals.find(j => j && j.id === journalId) || null;
}

function isUrbanAirHealthArticle(article) {
  if (!article || typeof article !== 'object') return false;
  if (typeof article.publicationYear !== 'number' || article.publicationYear < 2018 || article.publicationYear > 2023) return false;
  const journal = getJournal(article.journalId);
  const articleSubjects = Array.isArray(article.subjectAreas) ? article.subjectAreas : [];
  const journalSubjects = journal && Array.isArray(journal.subjectAreas) ? journal.subjectAreas : [];
  const combined = Array.from(new Set(articleSubjects.concat(journalSubjects)));
  if (!combined.includes('environmental_science') || !combined.includes('public_health')) return false;
  const textParts = [article.title || '', article.abstract || ''];
  if (Array.isArray(article.keywords)) textParts.push(article.keywords.join(' '));
  const text = textParts.join(' ').toLowerCase();
  const hasUrban = text.includes('urban') || text.includes('city') || text.includes('cities');
  const hasAirPollution = text.includes('air pollution') || text.includes('pm2.5') || text.includes('pm10') || text.includes('no2') || text.includes('particulate matter');
  const hasHealth = text.includes('health') || text.includes('mortality') || text.includes('asthma') || text.includes('hospital') || text.includes('respiratory') || text.includes('cardio') || text.includes('cohort');
  if (!hasUrban || !hasAirPollution || !hasHealth) return false;
  return true;
}

let maxQualifyingInAnyCollection = 0;
let hasCollectionAtLeast5 = false;
let hasCollection5And3Journals = false;

collections.forEach(col => {
  const colItemArticleIds = items
    .filter(ci => ci && ci.collectionId === col.id)
    .map(ci => ci.articleId);
  const uniqueArticleIds = Array.from(new Set(colItemArticleIds));
  const qualifyingArticles = uniqueArticleIds
    .map(id => articles.find(a => a && a.id === id) || null)
    .filter(a => isUrbanAirHealthArticle(a));
  const count = qualifyingArticles.length;
  if (count > maxQualifyingInAnyCollection) maxQualifyingInAnyCollection = count;
  if (count >= 5) {
    hasCollectionAtLeast5 = true;
    const journalIds = new Set(qualifyingArticles.map(a => a && a.journalId).filter(Boolean));
    if (journalIds.size >= 3) {
      hasCollection5And3Journals = true;
    }
  }
});

// CP1 (0.40): Some collection contains at least 3 qualifying urban air pollution health articles
checkpoints.push({ passed: maxQualifyingInAnyCollection >= 3, weight: 0.40 });

// CP2 (0.30): At least one collection contains 5 or more qualifying articles
checkpoints.push({ passed: hasCollectionAtLeast5, weight: 0.30 });

// CP3 (0.30): At least one collection contains 5+ qualifying articles from 3 or more distinct journals
checkpoints.push({ passed: hasCollection5And3Journals, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
